    ('PATIENT ASSESSMENT', 'EMT-B question bank content for PATIENT ASSESSMENT.', 3, 90, 150),
    ('MEDICAL/BEHAVIORAL EMERGENCIES AND OBSTETRICS/GYNECOLOGY', 'EMT-B question bank content for MEDICAL/BEHAVIORAL EMERGENCIES AND OBSTETRICS/GYNECOLOGY.', 4, 90, 170),
    ('TRAUMA', 'EMT-B question bank content for TRAUMA.', 5, 90, 80),
    ('INFANTS AND CHILDREN', 'EMT-B question bank content for INFANTS AND CHILDREN.', 6, 90, 100),
    ('OPERATIONS', 'EMT-B question bank content for OPERATIONS.', 7, 90, 90),
    ('ADVANCED AIRWAY (ELECTIVE)', 'EMT-B question bank content for ADVANCED AIRWAY (ELECTIVE).', 8, 90, 110),
    ('Additional Questions', 'EMT-B question bank content for Additional Questions.', 9, 90, 100)
