INSERT INTO mcq_modules (title, description, order_number, passing_score, total_questions)
SELECT seed.title, seed.description, seed.order_number, seed.passing_score, seed.total_questions
FROM module_seed seed
WHERE NOT EXISTS (
  SELECT 1
  FROM mcq_modules existing
  WHERE existing.title = seed.title
);

WITH question_seed (id, module_title, topic, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, difficulty) AS (
