    ('2f420b1c-1bc1-57f2-becd-edb1f15ecc56', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'Which of the following is NOT an assessment of mental status''', 'Alert', 'Responds to verbal stimuli', 'Skin color', 'Unresponsive', 'option_c', 'Correct answer: C. Skin color', 'intermediate'),
    ('fad55f08-9108-51a2-af13-79f32b04f499', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'For a trauma patient, the cervical spine should be stabilized:', 'Only after the airway is established', 'During airway management', 'Only if the patient complains of neck pain', 'After the initial assessment', 'option_b', 'Correct answer: B. During airway management', 'intermediate'),
    ('66dcf100-81cd-51e7-8381-29de8d2ea169', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'Patients with adequate breathing should receive:', 'No oxygen', 'High flow oxygen if indicated', 'Low flow oxygen only', 'Artificial ventilation', 'option_b', 'Correct answer: B. High flow oxygen if indicated', 'intermediate'),
    ('3cfb5426-b5f1-5d13-a407-b963528121d9', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'Patients with inadequate breathing should receive:', 'No intervention', 'Assisted breathing with ventilatory adjuncts and oxygen', 'Only oxygen', 'Only airway management', 'option_b', 'Correct answer: B. Assisted breathing with ventilatory adjuncts and oxygen', 'intermediate'),
    ('9966bfb9-7726-5cab-a2d3-e17116215e2c', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'A pulse should be assessed in an adult patient using the:', 'Brachial pulse', 'Carotid pulse only', 'Radial pulse', 'Femoral pulse', 'option_c', 'Correct answer: C. Radial pulse', 'intermediate'),
    ('ac137bfb-b3f0-50d6-9fb7-fe1be5ce8d63', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'In a patient one year old or less, the pulse should be assessed using the:', 'Carotid pulse', 'Radial pulse', 'Brachial pulse', 'Femoral pulse', 'option_c', 'Correct answer: C. Brachial pulse', 'intermediate'),
    ('bf4e2b4c-ffe2-5cf1-8c3d-4b4b1cdfb6b3', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'Capillary refill in infants and children should be assessed:', 'In the nail beds', 'In the palms of the hands', 'In the soles of the feet', 'Any of the above', 'option_d', 'Correct answer: D. Any of the above', 'intermediate'),
