    ('bc446208-93b5-585b-9954-1be774a7e0da', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'A patient with chest pain and BP <100 systolic should be considered:', 'Stable', 'A priority patient requiring expedited transport', 'A non-urgent patient', 'Not requiring emergency care', 'option_b', 'Correct answer: B. A priority patient requiring expedited transport', 'intermediate'),
    ('7f4c44fb-9837-5e53-b7c6-1303214d1d7c', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'The assessment of skin color includes looking at:', 'Nail beds, lips, and eyes', 'Only the face', 'Only the chest', 'Only the arms', 'option_a', 'Correct answer: A. Nail beds, lips, and eyes', 'intermediate'),
    ('8a468e8a-b648-57ba-b7f9-035f2f5fb6f7', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'Skin that is cyanotic appears:', 'Pink', 'Yellow', 'Blue-gray', 'Red', 'option_c', 'Correct answer: C. Blue-gray', 'intermediate'),
