    ('6af2d736-940e-565b-b287-6d8d344d6a53', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'AVPU stands for:', 'Alert, Verbal, Pain, Unresponsive', 'Airway, Ventilation, Pulse, Unresponsive', 'Alert, Ventilation, Pain, Unresponsive', 'Airway, Verbal, Pulse, Unresponsive', 'option_a', 'Correct answer: A. Alert, Verbal, Pain, Unresponsive', 'intermediate'),
