    ('c523cdba-91a6-5285-a8b9-5de9541a1f63', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'A patient who responds to verbal stimuli but is not alert is:', 'Alert', 'Responsive to verbal stimuli', 'Responsive to painful stimuli', 'Unresponsive', 'option_b', 'Correct answer: B. Responsive to verbal stimuli', 'intermediate'),
    ('a9be57c4-e58e-592d-ac03-3326bd813345', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'A patient who is alert and oriented is:', 'Aware of person, place, time, and event', 'Aware only of person', 'Aware only of place', 'Not aware of surroundings', 'option_a', 'Correct answer: A. Aware of person, place, time, and event', 'intermediate'),
