    ('07cc0728-eab4-5dca-9404-cc6f1fecb69f', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'The best indicator of brain injury is:', 'Skull fracture', 'Altered or decreasing mental status', 'Bleeding from the ears', 'Seizure activity', 'option_b', 'Correct answer: B. Altered or decreasing mental status', 'intermediate'),
    ('aaa119b1-e988-518a-b9a3-6ec5b1b29604', 'PATIENT ASSESSMENT', 'Lesson 3-2: Initial Assessment', 'Battle''s sign is:', 'Bruising around the eyes', 'Bruising behind the ears (mastoid process)', 'Bleeding from the nose', 'Fluid leakage from the ears', 'option_b', 'Correct answer: B. Bruising behind the ears (mastoid process)', 'intermediate'),
