    ('c5e7766a-5616-5438-b727-1b5d41f25885', 'PATIENT ASSESSMENT', 'Lesson 3-3: Focused History and Physical Exam - Trauma Patients', 'The SAMPLE history is:', 'Only obtained from trauma patients', 'Obtained from trauma and medical patients', 'Not necessary for trauma patients', 'Only obtained from responsive patients', 'option_b', 'Correct answer: B. Obtained from trauma and medical patients', 'intermediate'),
    ('642f71b1-fc9f-5f10-8a36-325ecbb69cca', 'PATIENT ASSESSMENT', 'Lesson 3-3: Focused History and Physical Exam - Trauma Patients', 'Cervical spine immobilization should be applied:', 'Only if the patient complains of neck pain', 'During the rapid trauma assessment', 'After the detailed physical exam', 'Only in the ambulance', 'option_b', 'Correct answer: B. During the rapid trauma assessment', 'intermediate'),
