    ('ddc71f02-bd05-584c-8cc3-3a4b5a051519', 'ADVANCED AIRWAY (ELECTIVE)', 'Lesson 7-4: Evaluation - Operations', 'In infants and children, the epiglottis:', 'Is larger and floppier than in adults', 'Is smaller than in adults', 'Is the same as in adults', 'Does not exist', 'option_a', 'Correct answer: A. Is larger and floppier than in adults', 'intermediate'),
    ('19239a8b-3903-5174-b4d2-41ace414cec2', 'ADVANCED AIRWAY (ELECTIVE)', 'Lesson 7-4: Evaluation - Operations', 'The Sellick maneuver (cricoid pressure) is used to:', 'Open the airway', 'Prevent passive regurgitation during intubation', 'Stop bleeding', 'Check for breath sounds', 'option_b', 'Correct answer: B. Prevent passive regurgitation during intubation', 'intermediate'),
