    ('712baf00-7ac4-5072-80be-7c16b0bf0dee', 'ADVANCED AIRWAY (ELECTIVE)', 'Lesson 7-4: Evaluation - Operations', 'A straight laryngoscope blade is:', 'Preferred in children and infants', 'Only used in adults', 'Used to lift the tongue', 'Not recommended for intubation', 'option_a', 'Correct answer: A. Preferred in children and infants', 'intermediate'),
    ('0d81dd15-d8f3-5c7e-9184-7a638ba6c2ff', 'ADVANCED AIRWAY (ELECTIVE)', 'Lesson 7-4: Evaluation - Operations', 'A curved laryngoscope blade is inserted into the:', 'Glottis', 'Vallecula', 'Trachea', 'Esophagus', 'option_b', 'Correct answer: B. Vallecula', 'intermediate'),
