    ('f0856536-b14f-53d9-af8c-1476b817d75a', 'ADVANCED AIRWAY (ELECTIVE)', 'Lesson 7-4: Evaluation - Operations', 'The formula for sizing an infant or child endotracheal tube is:', '16 + age in years divided by 4', '10 + age in years divided by 2', 'Age in years + 2', 'Age in years × 2', 'option_a', 'Correct answer: A. 16 + age in years divided by 4', 'intermediate'),
    ('34b9dfa9-a4e7-5a8c-8ad2-792e61ab9052', 'ADVANCED AIRWAY (ELECTIVE)', 'Lesson 7-4: Evaluation - Operations', 'The typical size of an endotracheal tube for an adult male is:', '6.0-6.5 mm', '7.0-7.5 mm', '8.0-8.5 mm', '9.0-9.5 mm', 'option_c', 'Correct answer: C. 8.0-8.5 mm', 'intermediate'),
    ('f2474e04-fd2a-5468-8402-076d955769e2', 'ADVANCED AIRWAY (ELECTIVE)', 'Lesson 7-4: Evaluation - Operations', 'Before an intubation attempt, the patient should be hyperventilated at:', '12 breaths per minute', '20 breaths per minute', '24 breaths per minute', '30 breaths per minute', 'option_c', 'Correct answer: C. 24 breaths per minute', 'intermediate'),
    ('2286c8b8-c285-5004-9f8c-0f3d6b8b4cb0', 'ADVANCED AIRWAY (ELECTIVE)', 'Lesson 7-4: Evaluation - Operations', 'The stylet in endotracheal intubation:', 'Is not needed', 'Provides stiffness and shape to the tube', 'Is used to check breath sounds', 'Is used to suction the airway', 'option_b', 'Correct answer: B. Provides stiffness and shape to the tube', 'intermediate'),
