INSERT INTO mcq_questions (id, module_id, topic, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, difficulty)
SELECT seed.id::uuid,
       m.id,
       seed.topic,
       seed.question_text,
       seed.option_a,
       seed.option_b,
       seed.option_c,
       seed.option_d,
       seed.correct_option,
       seed.explanation,
       seed.difficulty
FROM question_seed seed
JOIN mcq_modules m ON m.title = seed.module_title
ON CONFLICT (id) DO NOTHING;
